from itertools import combinations, chain, product
from functools import lru_cache
from collections import Counter, defaultdict

def ordered_partitions(n,k):
    # Generate all ordered set partitions by assigning each element to block 0..k-1 surjectively, then collect blocks
    # This overcounts? No each ordered partition corresponds to unique function element->block.
    for ass in product(range(k), repeat=n):
        if set(ass)==set(range(k)):
            blocks=[set() for _ in range(k)]
            for i,b in enumerate(ass, start=1):
                blocks[b].add(i)
            yield tuple(frozenset(b) for b in blocks)

def inv_stat(blocks):
    inv=0
    # pairs (i,j) i<j, i=min B_m, j in B_l, l<m
    k=len(blocks)
    for m,Bm in enumerate(blocks):
        i=min(Bm)
        for ell in range(m):
            for j in blocks[ell]:
                if i<j:
                    inv += 1
    return inv

def poly_add(p,q):
    r=Counter(p)
    for exp,c in q.items():
        r[exp]+=c
    return Counter({e:c for e,c in r.items() if c})
def poly_mul(p,q):
    r=Counter()
    for e1,c1 in p.items():
        for e2,c2 in q.items():
            r[e1+e2]+=c1*c2
    return Counter({e:c for e,c in r.items() if c})
def qint(k):
    return Counter({i:1 for i in range(k)})
def poly_str(p):
    if not p: return "0"
    return " + ".join(f"{c}q^{e}" if e else str(c) for e,c in sorted(p.items()))

@lru_cache(None)
def stir_poly(n,k):
    if n==0 and k==0: return Counter({0:1})
    if n<0 or k<0 or k>n: return Counter()
    # Stir(n,k)=Stir(n-1,k-1)+[k]Stir(n-1,k)
    return poly_add(stir_poly(n-1,k-1), poly_mul(qint(k), stir_poly(n-1,k)))

def qfact(k):
    p=Counter({0:1})
    for i in range(1,k+1):
        p=poly_mul(p,qint(i))
    return p

def F_poly(r,k):
    return poly_mul(qfact(k), stir_poly(r,k))

def enum_F(r,k):
    c=Counter()
    for blocks in ordered_partitions(r,k):
        c[inv_stat(blocks)] += 1
    return c

for r in range(1,7):
    for k in range(1,r+1):
        assert F_poly(r,k)==enum_F(r,k), (r,k,F_poly(r,k),enum_F(r,k))
print("F matches OP inversion enumerator for r<=6")

# Compare claimed G_n with (H_n-1)/(q+z) via recursion formula (not polynomial division) and direct restricted partitions
def G_from_formula(n):
    # dict z_exp -> Counter q
    d=defaultdict(Counter)
    for r in range(1,n):
        for k in range(1,r+1):
            d[r-k] = poly_add(d[r-k], poly_mul(qint(k), F_poly(r,k)))
    return {z:p for z,p in d.items() if p}
def G_from_restricted(n):
    d=defaultdict(Counter)
    for r in range(2,n+1):
        for k in range(1,r):
            for blocks in ordered_partitions(r,k):
                if len(blocks) == k:
                    # r not a singleton block
                    if any((r in B and len(B)==1) for B in blocks):
                        continue
                    d[r-k-1][inv_stat(blocks)] += 1
    return {z:Counter(p) for z,p in d.items() if p}

for n in range(1,7):
    gf=G_from_formula(n)
    gr=G_from_restricted(n)
    assert gf==gr, (n,gf,gr)
    print("n",n, "G", {z: dict(poly) for z,poly in sorted(gf.items())})
